class Solution {
public:
    vector<string> removeInvalidParentheses(string s) {
        vector<string> res;
        int rmL = 0, rmR = 0;
        for (char c : s) {
            if (c == '(') rmL++;
            else if (c == ')') {
                if (rmL == 0) rmR++;
                else rmL--;
            }
        }
        dfs(s, 0, rmL, rmR, "", res);
        return res;
    }
private:
    void dfs(string s, int i, int rmL, int rmR, string path, vector<string>& res) {
        if (i == s.size()) {
            if (rmL == 0 && rmR == 0) res.push_back(path);
            return;
        }
        if (s[i] == '(') {
            if (rmL > 0) dfs(s, i + 1, rmL - 1, rmR, path, res);
            dfs(s, i + 1, rmL, rmR, path + "(", res);
        } else if (s[i] == ')') {
            if (rmR > 0) dfs(s, i + 1, rmL, rmR - 1, path, res);
            if (rmL > 0) dfs(s, i + 1, rmL - 1, rmR, path + ")", res);
        } else {
            dfs(s, i + 1, rmL, rmR, path + s[i], res);
        }
    }
};
